
var content; //Armazena a referência para a tag de conteúdo da página
var wsUrlObra = "wsObra.php"; //endereço do WS a ser consultado
var wsUrlObra = "wsUsuario.php";
$(document).ready(function () {
    obra = $("#Obra");//Obtém a referência para a tag de conteúdo depois da página carregada
    user = $("#User");
});

/**
 * Realiza a chamada ao WS como GET, consulta
 * @param {int} where - ID a ser consultado no banco
 * @returns {undefined}
 */
function doGet(where) {
    $.ajax({
        type: "GET",
        url: wsUrl,
        data: where,
        contentType: "application/json; charset=utf-8",
        dataType: "json",
        success: function (data) {
            formatObras(data.itens); //Em caso de sucesso chamar função de impressão
        },
        failure: function (errMsg) {
            console.log(errMsg);
        }
    });
}

/**
 * 
 * @param {type} metodo
 * @returns {undefined}
 */
function doPost(metodo) {

    switch (metodo) {

        case "Obra":
            var name = $('#wNomeObra');
            var preco = $('#wPreco');
            var width = $('#wLargura');
            var hight = $('#wAltura');
            var desc = $('#wDescricao');
            var date = $('#wDataCriacao');
            var id = $('#wIdArtista');
            $.ajax({
                type: "POST",
                url: "wsObra.php",
                data: JSON.stringify({'nomeObra': name.val(), 'preco': preco.val(),
                    'largura': width.val(), 'altura': hight.val(),
                    'descricao': desc.val(), 'dataObra': date.val(),
                    'idArtista': id.val()}),
                contentType: "application/json; charset=utf-8",
                dataType: "json",
                success: function (data) {
                    $(obra).text(data.itens); //Imprime o retorno do WS na tag de conteúdo
                },
                failure: function (errMsg) {
                    alert(errMsg);
                }
            });
            break;
        case "User":
            var name = $('#wNome');
            var nick = $('#wNick');
            var sexo = $('#wSexo');
            var email = $('#wEmail');
            var senha = $('#wSenha');
            var desc = $('#wDesc');
            var date = $('wData');
            
            $.ajax({
                type: "POST",
                url: "wsUsuario.php",
                data: JSON.stringify({'nome': name.val(), 'nickname': nick.val(),
                    'sexo': sexo.val(), 'email': email.val(),
                    'senha': senha.val(), 'descricao': desc.val(),
                    'dataNascimento': date.val()}),
                contentType: "application/json; charset=utf-8",
                dataType: "json",
                success: function (data) {
                    $(user).text(data.itens); //Imprime o retorno do WS na tag de conteúdo
                },
                failure: function (errMsg) {
                    alert(errMsg);
                }
            });
            break;
        case "Evento":
            var nomeEvento = $('#wNomeEvento');
            var local = $('#wLocal');
            var dataEvento = $('#wDataEvento');
            var desc = $('#wDescricao');
            var idOrg = $('#wIdOrganizador');
            $.ajax({
                type: "POST",
                url: "wsEvento.php",
                data: JSON.stringify({'nome': nomeEvento.val(), 'local': local.val(),
                    'dataHora': dataEvento.val(), 'descricao': desc.val(),
                    'idOrganizador': idOrg.val()}),
                contentType: "application/json; charset=utf-8",
                dataType: "json",
                success: function (data) {
                    $(user).text(data.itens); //Imprime o retorno do WS na tag de conteúdo
                },
                failure: function (errMsg) {
                    alert(errMsg);
                }
            });
            break;
    }
}

/**
 * Realiza a chamada do WS como DELETE, deleção
 * @param {int} id - Recebe o ID do objeto que deve ser deletado
 * @returns {undefined}
 */
function doDelete(id) {
    $.ajax({
        type: "DELETE",
        url: wsUrl + "/" + id, // No caso da deleção, o ID deve ser concatenado à URL do WS, separado por "/"
        contentType: "application/json; charset=utf-8",
        dataType: "json",
        success: function (data) {
            $(content).text(data.itens); //Imprime o retorno do WS na tag de conteúdo
        },
        failure: function (errMsg) {
            alert(errMsg);
        }
    });
}

