/**
 * Cria uma <div> para cada objeto recebido
 * @param {array} obras - Listass das obras
 * @param {boolean} deleted - Se deve ou não habilitar o botão de delete
 * @returns {undefined}
 */
function formatObras(obras, deleted = false) {

    content.html("");
    for (var w in obras) {
        w = obras[w];
        div = document.createElement("div");
        div.appendChild(createInput(w.idObra + "id", w.idObra, true));
        div.appendChild(createInput(w.idObra + "nome", w.nome));
        div.appendChild(createInput(w.idObra + "valor", w.preco));
        div.appendChild(createInput(w.idObra + "descricao", w.descricao));
        div.appendChild(createInput(w.idObra + "altura", w.altura));
        div.appendChild(createInput(w.idObra + "altura", w.largura));
        div.appendChild(createInput(w.idObra + "data", w.dataObra));
//        div.appendChild(createUpdateButton(w.idObra, deleted));
        div.appendChild(createDeleteButton(w.idObra, deleted));
        content.append(div);
}
}

//Cria as caixas de entrada com os valores dos campos
function createInput(id, value, disabled = false) {
    input = document.createElement("input");
    $(input).attr("id", "id" + id);
    $(input).attr("value", value);
    $(input).attr("disabled", disabled);
    return input;
}

//Cria campo com a imagem do objeto
function createImg(id) {
    img = document.createElement("img");
    $(img).attr("src", "img/product/" + id + ".png");
    return img;
}

//Cria o botão de Update
function createUpdateButton(id, disabled) {
    input = document.createElement("input");
    $(input).attr("type", "button");
    $(input).attr("value", "PUT");
    $(input).attr("disabled", disabled);
    $(input).attr("onclick", "doPut($('#id" + id + "id').val(), $('#id" + id + "nome').val(), $('#id" + id + "valor').val())");
    return input;
}

//Cria o botão de Delete
function createDeleteButton(id, disabled) {
    input = document.createElement("input");
    $(input).attr("type", "button");
    $(input).attr("value", "DELETE");
    $(input).attr("disabled", disabled);
    $(input).attr("onclick", "doDelete(" + id + ")");
    return input;
}

